 ;


   java
public PaymentResponse process String idempotencyKey, PaymentRequest request  {
    try {
        Payment payment = Payment.create idempotencyKey, request ;
        paymentRepository.save payment ; // unique 위반 시 예외
        externalPaymentGateway.charge payment ;
        return PaymentResponse.from payment ;
    } catch  DataIntegrityViolationException e  {
        // 이미 처리된 요청 — 기존 결과 반환
        return paymentRepository.findByIdempotencyKey idempotencyKey 
            .map PaymentResponse::from 
            .orElseThrow  ;
    }
}


