사용자별로 디바이스마다 별도의 Refresh Token을 관리한다.

   java
// RefreshToken 엔티티 — 디바이스별 관리
@Entity
public class RefreshToken {
    @Id @GeneratedValue
    private Long id;

    private Long userId;
    private String token;
    private String deviceInfo;  // User-Agent 등
    private LocalDateTime createdAt;
    private LocalDateTime expiresAt;
}


   java
// 로그인 시 디바이스 정보와 함께 저장
public TokenResponse login LoginRequest request, String userAgent  {
    // ...
    refreshTokenRepository.save 
        RefreshToken.of user.getId  , refreshToken, userAgent 
     ;
    return new TokenResponse accessToken, refreshToken ;
}

// 특정 디바이스만 로그아웃
public void logoutDevice Long userId, String deviceInfo  {
    refreshTokenRepository.deleteByUserIdAndDeviceInfo userId, deviceInfo ;
}

// 모든 디바이스 로그아웃
public void logoutAll Long userId  {
    refreshTokenRepository.deleteAllByUserId userId ;
}


